<?php
// Generated by Cursor prompt — module: Finans (AdvanceRequest) — date: 2026-03-15

namespace App\Modules\Finans\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\SoftDeletes;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Support\Facades\DB;

class AdvanceRequest extends Model
{
    use SoftDeletes;

    protected $table = 'advance_requests';

    protected $fillable = [
        'company_id', 'personel_id', 'amount', 'currency',
        'reason', 'status', 'repayment_plan', 'approved_by',
        'approved_at', 'rejection_reason', 'created_by',
    ];

    protected $casts = [
        'amount'         => 'decimal:2',
        'repayment_plan' => 'array',
        'approved_at'    => 'datetime',
    ];

    const STATUS_PENDING   = 'pending';
    const STATUS_APPROVED  = 'approved';
    const STATUS_REJECTED  = 'rejected';
    const STATUS_CANCELLED = 'cancelled';
    const STATUS_REPAID    = 'repaid';

    // ─── Relations ───────────────────────────────────────────────────────────

    public function personel(): BelongsTo
    {
        return $this->belongsTo(\App\Modules\Personel\Models\Personel::class);
    }

    public function approver(): BelongsTo
    {
        return $this->belongsTo(\App\Models\User::class, 'approved_by');
    }

    public function createdBy(): BelongsTo
    {
        return $this->belongsTo(\App\Models\User::class, 'created_by');
    }

    // ─── İş Mantığı ──────────────────────────────────────────────────────────

    public function approve(int $approverId, ?array $repaymentPlan = null): array
    {
        if ($this->status !== self::STATUS_PENDING) {
            return ['success' => false, 'message' => 'Bu talep zaten işlenmiş.'];
        }

        $this->update([
            'status'          => self::STATUS_APPROVED,
            'approved_by'     => $approverId,
            'approved_at'     => now(),
            'repayment_plan'  => $repaymentPlan,
        ]);

        DB::table('audit_logs')->insert([
            'user_id'    => $approverId,
            'company_id' => $this->company_id,
            'action'     => 'advance_request.approved',
            'model_type' => self::class,
            'model_id'   => $this->id,
            'changes'    => json_encode(['amount' => $this->amount, 'currency' => $this->currency]),
            'ip'         => request()->ip(),
            'created_at' => now(),
        ]);

        return ['success' => true, 'message' => 'Avans talebi onaylandı.'];
    }

    public function reject(int $rejectorId, string $reason): array
    {
        if ($this->status !== self::STATUS_PENDING) {
            return ['success' => false, 'message' => 'Bu talep zaten işlenmiş.'];
        }

        $this->update([
            'status'           => self::STATUS_REJECTED,
            'rejection_reason' => $reason,
        ]);

        return ['success' => true, 'message' => 'Avans talebi reddedildi.'];
    }

    public function cancel(int $userId): array
    {
        if (in_array($this->status, [self::STATUS_APPROVED, self::STATUS_REPAID])) {
            return ['success' => false, 'message' => 'Onaylı veya ödenmiş talep iptal edilemez.'];
        }
        $this->update(['status' => self::STATUS_CANCELLED]);
        return ['success' => true, 'message' => 'Avans talebi iptal edildi.'];
    }

    public function getStatusLabelAttribute(): string
    {
        return match ($this->status) {
            'pending'   => 'Bekliyor',
            'approved'  => 'Onaylandı',
            'rejected'  => 'Reddedildi',
            'cancelled' => 'İptal',
            'repaid'    => 'Ödendi',
            default     => $this->status,
        };
    }

    public function getStatusColorAttribute(): string
    {
        return match ($this->status) {
            'pending'   => 'yellow',
            'approved'  => 'green',
            'rejected'  => 'red',
            'cancelled' => 'gray',
            'repaid'    => 'blue',
            default     => 'gray',
        };
    }

    public function scopeForCompany($query, int $companyId)
    {
        return $query->where('company_id', $companyId);
    }

    public function scopePending($query)
    {
        return $query->where('status', self::STATUS_PENDING);
    }
}
